const body = $input.first().json.body || $input.first().json;

if (!body?.data?.message) return [];

const data = body.data;
if (data.key?.fromMe === true) return [];

const remoteJid = data.key?.remoteJid || '';
if (remoteJid.includes('@g.us') || remoteJid.match(/\d+-\d+@/)) return [];

const mensaje = data.message?.conversation ||
                data.message?.extendedTextMessage?.text ||
                data.message?.imageMessage?.caption || '';
if (!mensaje.trim()) return [];

const numero = remoteJid.replace('@s.whatsapp.net','').replace('@lid','');
const nombre  = data.pushName || 'Cliente';
const instancia = body.instance || data.owner || '';
const ciudad = instancia.includes('med') ? 'medellin' : 'bogota';

return [{ json: { numero, mensaje: mensaje.trim(), nombre, instancia, ciudad } }];

const { numero, mensaje, nombre, instancia, ciudad } = $input.first().json;

const now = new Date();
const col = new Date(now.toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const day = col.getDay();
const t = col.getHours() * 60 + col.getMinutes();
const T = (h, m=0) => h*60+(m||0);

let botActivo = false;

if (ciudad === 'bogota') {
  // Lun-Jue 22:00-08:00 | Vie 18:00-Sab 08:00 | Sab 17:00-Dom 09:00 | Dom 16:00-Lun 08:00
  if (day>=1 && day<=4) botActivo = t>=T(22) || t<T(8);
  else if (day===5)     botActivo = t>=T(18) || t<T(8);
  else if (day===6)     botActivo = t<T(8)   || t>=T(17);
  else if (day===0)     botActivo = t<T(9)   || t>=T(16);
} else {
  // Medellin: Lun-Jue 18:00-08:00 | Vie 18:00-Sab 08:00 | Sab 17:00-Dom 09:00 | Dom 13:00-Lun 08:00
  if (day>=1 && day<=4) botActivo = t>=T(18) || t<T(8);
  else if (day===5)     botActivo = t>=T(18) || t<T(8);
  else if (day===6)     botActivo = t<T(8)   || t>=T(17);
  else if (day===0)     botActivo = t<T(9)   || t>=T(13);
}

return [{ json: { numero, mensaje, nombre, instancia, ciudad, botActivo } }];
